+import type { AnyColumn } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { SQL, sql, type SQLWrapper } from '../sql.ts';
+
+export type WindowBoundary =
+	| typeof unboundedPreceding
+	| typeof currentRow
+	| typeof unboundedFollowing
+	| { type: 'preceding' | 'following'; value: number };
+
+export interface WindowFrame {
+	type: 'rows' | 'range';
+	from: WindowBoundary;
+	to: WindowBoundary;
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+export const unboundedPreceding = { type: 'unbounded preceding' } as const;
+export const currentRow = { type: 'current row' } as const;
+export const unboundedFollowing = { type: 'unbounded following' } as const;
+
+function validateOffset(name: string, value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+}
+
+export function preceding(value: number) {
+	validateOffset('preceding', value);
+	return { type: 'preceding' as const, value };
+}
+
+export function following(value: number) {
+	validateOffset('following', value);
+	return { type: 'following' as const, value };
+}
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	if (boundary === unboundedPreceding) return -Infinity;
+	if (boundary === unboundedFollowing) return Infinity;
+	if (boundary === currentRow) return 0;
+	return boundary.type === 'preceding' ? -boundary.value : boundary.value;
+}
+
+function frame(type: WindowFrame['type'], spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	if (boundary === unboundedPreceding) return sql.raw('unbounded preceding');
+	if (boundary === unboundedFollowing) return sql.raw('unbounded following');
+	if (boundary === currentRow) return sql.raw('current row');
+	return sql.raw(`${boundary.value} ${boundary.type}`);
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy === undefined ? [] : (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]);
+	const orderBy = spec.orderBy === undefined ? [] : (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]);
+	const partitionSql = partitionBy.length ? sql`partition by ${sql.join(partitionBy, sql`, `)}` : undefined;
+	const orderSql = orderBy.length ? sql`order by ${sql.join(orderBy, sql`, `)}` : undefined;
+	const frameSql = spec.frame
+		? sql`${sql.raw(spec.frame.type)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}`
+		: undefined;
+	return sql.join([partitionSql, orderSql, frameSql].filter((item): item is SQL => item !== undefined), sql` `);
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+
+	getSQL(): SQL<T> {
+		return this.expression;
+	}
+}
+
+function fn<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})` as SQL<T>);
+}
+
+function positional(name: string, value: number): SQL {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer, received ${value}`);
+	return sql.raw(String(value));
+}
+
+function valueArg(value: unknown): SQLWrapper {
+	return value as SQLWrapper;
+}
+
+export function rowNumber(): WindowFunction<number> { return fn('row_number'); }
+export function rank(): WindowFunction<number> { return fn('rank'); }
+export function denseRank(): WindowFunction<number> { return fn('dense_rank'); }
+export function ntile(buckets: number): WindowFunction<number> { return fn('ntile', [positional('ntile', buckets)]); }
+export function percentRank(): WindowFunction<number> { return fn('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return fn('cume_dist'); }
+
+type ValueType<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer U> ? U : unknown;
+type DefaultValue<T extends SQLWrapper, TDefault> = TDefault extends undefined ? ValueType<T> | null : Exclude<ValueType<T>, null>;
+
+export function lag<T extends SQLWrapper, TDefault = undefined>(value: T, offset?: number, defaultValue?: TDefault): WindowFunction<DefaultValue<T, TDefault>> {
+	const args: SQLWrapper[] = [value];
+	if (offset !== undefined) args.push(sql.raw(String(offset)));
+	if (defaultValue !== undefined) args.push(valueArg(defaultValue));
+	return fn('lag', args);
+}
+export function lead<T extends SQLWrapper, TDefault = undefined>(value: T, offset?: number, defaultValue?: TDefault): WindowFunction<DefaultValue<T, TDefault>> {
+	const args: SQLWrapper[] = [value];
+	if (offset !== undefined) args.push(sql.raw(String(offset)));
+	if (defaultValue !== undefined) args.push(valueArg(defaultValue));
+	return fn('lead', args);
+}
+export function firstValue<T extends SQLWrapper>(value: T): WindowFunction<ValueType<T> | null> { return fn('first_value', [value]); }
+export function lastValue<T extends SQLWrapper>(value: T): WindowFunction<ValueType<T> | null> { return fn('last_value', [value]); }
+export function nthValue<T extends SQLWrapper>(value: T, nth: number): WindowFunction<ValueType<T> | null> { return fn('nth_value', [value, positional('nthValue', nth)]); }
+
+export function windowSum(value: SQLWrapper): WindowFunction<string | null> { return fn('sum', [value]); }
+export function windowAvg(value: SQLWrapper): WindowFunction<string | null> { return fn('avg', [value]); }
+export function windowMin<T extends SQLWrapper>(value: T): WindowFunction<(ValueType<T>) | null> { return fn('min', [value]); }
+export function windowMax<T extends SQLWrapper>(value: T): WindowFunction<(ValueType<T>) | null> { return fn('max', [value]); }
+export function windowCount(value?: SQLWrapper): WindowFunction<number> { return fn('count', [value ?? sql.raw('*')]); }
